import{_ as a,o,c as i,S as r}from"./chunks/framework.058ce8a4.js";const e="/img/map-settings/eurotier.webp",n="/img/map-settings/center.webp",s="/img/map-settings/centerxy.webp",m="/img/map-settings/demo.webp",p="/img/map-settings/z.webp",c="/img/map-settings/kiosk.webp",l="/img/map-settings/bearing.webp",d="/img/map-settings/zoom.webp",g="/img/map-settings/zoomtime_500.mp4",h="/img/map-settings/zoomtime_5000.mp4",w=JSON.parse('{"title":"Configuring Map Settings via URL Parameters","description":"","frontmatter":{},"headers":[],"relativePath":"js-sdk-v2/configuring-map-guide.md","lastUpdated":1777917137000}'),u={name:"js-sdk-v2/configuring-map-guide.md"};function b(f,t,z,y,v,_){return o(),i("div",null,t[0]||(t[0]=[r('<h1 id="configuring-map-settings-via-url-parameters" tabindex="-1">Configuring Map Settings via URL Parameters <a class="header-anchor" href="#configuring-map-settings-via-url-parameters" aria-label="Permalink to &quot;Configuring Map Settings via URL Parameters&quot;">​</a></h1><h2 id="map-settings-overview" tabindex="-1">Map Settings Overview <a class="header-anchor" href="#map-settings-overview" aria-label="Permalink to &quot;Map Settings Overview&quot;">​</a></h2><p>You can customize your map experience by adjusting settings directly in the URL. Here’s a quick guide to the available parameters:</p><h3 id="center" tabindex="-1"><strong>center</strong> <a class="header-anchor" href="#center" aria-label="Permalink to &quot;**center**&quot;">​</a></h3><p>Defines the map center using WGS84 coordinates (latitude, longitude).<br> Example: <code>?center=52.31801546937824,9.803534426718189</code></p><p><em>Default</em><img loading="lazy" src="'+e+'" alt=""></p><p><em>With parameter</em><img loading="lazy" src="'+n+'" alt=""></p><hr><h3 id="centerxy" tabindex="-1"><strong>centerxy</strong> <a class="header-anchor" href="#centerxy" aria-label="Permalink to &quot;**centerxy**&quot;">​</a></h3><p>Sets the map center using projected coordinates (x, y).<br> Example: <code>?centerxy=6517.28955078125,3826.6064453125</code></p><p><em>Default</em><img loading="lazy" src="'+e+'" alt=""></p><p><em>With parameter</em><img loading="lazy" src="'+s+'" alt=""></p><hr><h3 id="z" tabindex="-1"><strong>z</strong> <a class="header-anchor" href="#z" aria-label="Permalink to &quot;**z**&quot;">​</a></h3><p>Specifies the floor/level name.<br> Example: <code>?z=2</code></p><p><em>Default</em><img loading="lazy" src="'+m+'" alt=""></p><p><em>With parameter</em><img loading="lazy" src="'+p+'" alt=""></p><hr><h3 id="bearing" tabindex="-1"><strong>bearing</strong> <a class="header-anchor" href="#bearing" aria-label="Permalink to &quot;**bearing**&quot;">​</a></h3><p>Rotates the kiosk arrow icon (0–360 degrees).</p><blockquote><p><em>Currently works only in kiosk mode.</em></p></blockquote><p>Example: <code>?bearing=180</code></p><p><em>Default</em><img loading="lazy" src="'+c+'" alt=""></p><p><em>With parameter</em><img loading="lazy" src="'+l+'" alt=""></p><hr><h3 id="zoom" tabindex="-1"><strong>zoom</strong> <a class="header-anchor" href="#zoom" aria-label="Permalink to &quot;**zoom**&quot;">​</a></h3><p>Adjusts the zoom level (1–100).<br> Example: <code>?zoom=5</code></p><p><em>Default</em><img loading="lazy" src="'+e+'" alt=""></p><p><em>With parameter</em><img loading="lazy" src="'+d+'" alt=""></p><hr><h3 id="zoomtime" tabindex="-1"><strong>zoomtime</strong> <a class="header-anchor" href="#zoomtime" aria-label="Permalink to &quot;**zoomtime**&quot;">​</a></h3><p>Sets the zoom animation duration in milliseconds (range: 500–5000).<br> Example: <code>?zoomtime=5000</code></p><p><em>?zoomtime=500</em><video controls><source src="'+g+'" type="video/mp4"></video></p><p><em>?zoomtime=5000</em><video controls><source src="'+h+'" type="video/mp4"></video></p><h2 id="how-to-reset-settings" tabindex="-1">How to Reset Settings? <a class="header-anchor" href="#how-to-reset-settings" aria-label="Permalink to &quot;How to Reset Settings?&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><p><strong>Important Note</strong>: Settings are applied only to the specific map they are sent to and only on the device where they are applied.</p></div><p>Settings do not accumulate — each time new settings are sent, they overwrite the previous ones.</p><p><strong>Example</strong>:</p><p>If you open a card with <code>?bearing=45</code> and later open it again with <code>?zoom=5</code>, the <code>bearing=45</code> setting will not be applied — only <code>zoom=5</code> will take effect. In other words, if you need both settings, you must include them in the same request: <code>?bearing=45&amp;zoom=5</code>.</p><p><strong>To cancel a previously applied setting</strong> (e.g., <code>zoom=5</code>), you can set a new value (e.g., <code>zoom=1</code>).</p><hr><p>Also, check out the <a href="/js-sdk-v2/query-parameters">full documentation</a>.</p>',42)]))}const x=a(u,[["render",b]]);export{w as __pageData,x as default};
